SELECT * FROM product

    AND product_type = #{productType}
    AND risk_level = #{riskLevel}
    AND status = #{status}
    AND product_code LIKE CONCAT('%',#{productCode},'%')
    AND product_name LIKE CONCAT('%',#{productName},'%')

ORDER BY id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM product

    AND product_type = #{productType}
    AND risk_level = #{riskLevel}
    AND status = #{status}
    AND product_code LIKE CONCAT('%',#{productCode},'%')
    AND product_name LIKE CONCAT('%',#{productName},'%')
